// Node: "Prepare Attachments"
// Attachments are already downloaded as binary by the Gmail Trigger
// (downloadAttachments: true). This node normalizes their metadata so the
// Airtable attach step can iterate them, and passes binaries straight
// through — no local disk staging needed.
const item = $input.first();
const attachmentMeta = Object.entries(item.binary || {}).map(([key, bin]) => ({
  binaryKey: key,
  fileName: bin.fileName || key,
  mimeType: bin.mimeType || 'application/octet-stream',
}));
return [{ json: { ...item.json, attachmentMeta }, binary: item.binary }];

// Node: "Merge VIP Flag"
// If the Customers lookup found a record, carry its VIP flag forward.
// If absent, the VIP override rule is skipped gracefully (vip_flag = false).
const meta = $('Merge - Attachment Branches').first().json;
const lookup = $input.first().json;
const vip_flag = !!(lookup && lookup.fields && (lookup.fields['VIP Flag'] === true));
return [{ json: { ...meta, vip_flag }, binary: $('Merge - Attachment Branches').first().binary }];

// Node: "Validate & Clean AI Output"
function safeJsonParse(raw) {
  try {
    const cleaned = raw.replace(/```json|```/g, '').trim();
    return JSON.parse(cleaned);
  } catch (e) {
    throw new Error(`AI_JSON_PARSE_ERROR: ${e.message} | raw: ${String(raw).slice(0, 200)}`);
  }
}

const ALLOWED_CATEGORIES = ["Technical Support","Billing","Sales Inquiry",
  "Feature Request","Bug Report","Account Access","Refund Request",
  "General Inquiry","Other"];
const ALLOWED_PRIORITIES = ["Critical","High","Medium","Low"];
const ALLOWED_SENTIMENT = ["Positive","Neutral","Negative"];

function normalizeEnum(value, allowed, fallback) {
  if (!value) return fallback;
  const match = allowed.find(a => a.toLowerCase() === String(value).toLowerCase());
  return match || fallback;
}

function dedupeTags(tags) {
  return [...new Set((tags || []).map(t => String(t).trim().toLowerCase()))]
    .filter(Boolean)
    .map(t => t.charAt(0).toUpperCase() + t.slice(1));
}

function validateEmail(email) {
  const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return email && re.test(email) ? String(email).toLowerCase() : null;
}

const raw = $input.first().json.content?.[0]?.text || $input.first().json.text;
let data;
let parseFailed = false;
try {
  data = safeJsonParse(raw);
} catch (e) {
  // Malformed-response policy: never silently drop a ticket. Fall back to
  // safe defaults, keep the raw output for agent visibility, and flag review.
  parseFailed = true;
  data = {};
}

const cleaned = {
  customer_name: data.customer_name?.trim() || 'Unknown',
  company: data.company?.trim() || null,
  issue_summary: data.issue_summary?.trim() || 'No summary generated',
  detailed_description: data.detailed_description?.trim() || '',
  category: normalizeEnum(data.category, ALLOWED_CATEGORIES, 'General Inquiry'),
  priority: normalizeEnum(data.priority, ALLOWED_PRIORITIES, 'Medium'),
  priority_justification: data.priority_justification?.trim() || '',
  sentiment: normalizeEnum(data.sentiment, ALLOWED_SENTIMENT, 'Neutral'),
  product_service: data.product_service?.trim() || null,
  suggested_department: data.suggested_department?.trim() || 'General Support',
  suggested_tags: dedupeTags(data.suggested_tags),
  detected_language: data.detected_language || 'en',
  confidence_score: typeof data.confidence_score === 'number'
    ? Math.min(1, Math.max(0, data.confidence_score)) : 0.5,
};

// Fallback: use sender email from metadata, never rely solely on AI-guessed email
const meta = $('Code - Merge VIP Flag').first().json;
cleaned.sender_email = validateEmail(meta.senderEmail);
cleaned.vip_flag = meta.vip_flag;

// Low-confidence guard: force human review regardless of category/priority
cleaned.needs_manual_review = parseFailed || cleaned.confidence_score < 0.6;
cleaned.raw_ai_output_note = parseFailed
  ? `AI JSON parse failed. Raw output: ${String(raw).slice(0, 1000)}`
  : '';

return [{ json: { ...meta, ...cleaned }, binary: $('Code - Merge VIP Flag').first().binary }];

// Node: "Priority Business Rules" (AI + deterministic hybrid)
let priority = $json.priority;
const bodyLower = ($json.detailed_description + ' ' + $json.body).toLowerCase();

const CRITICAL_KEYWORDS = ['outage', 'down', 'security breach', 'data loss', 'cannot login for all users', 'payment failed for all'];
const HIGH_KEYWORDS = ['urgent', 'asap', 'escalate', 'angry', 'cancel my subscription'];

// Deterministic override: keyword match forces minimum priority floor
if (CRITICAL_KEYWORDS.some(k => bodyLower.includes(k))) {
  priority = 'Critical';
} else if (HIGH_KEYWORDS.some(k => bodyLower.includes(k)) && priority === 'Medium') {
  priority = 'High';
}

// VIP customer override (populated by the earlier Airtable lookup)
const isVip = $json.vip_flag === true;
if (isVip && priority === 'Low') priority = 'Medium';

return [{ json: { ...$json, priority, priority_source: priority !== $json.priority ? 'business_rule_override' : 'ai' }, binary: $input.first().binary }];

// Node: "Duplicate Ticket Check" (bonus)
// Idempotency first: exact Gmail messageId match means this trigger re-fired
// on an already-processed email — treat as hard duplicate.
// Then fuzzy match: same sender + issue-summary token overlap >= 0.6 within
// the 7-day window of open tickets fetched by the previous node.
const ticket = $('Code - Priority Business Rules').first().json;
const candidates = $input.all().map(i => i.json).filter(j => j && j.fields);

function tokenSet(s) {
  return new Set(String(s || '').toLowerCase().replace(/[^a-z0-9\s]/g, '').split(/\s+/).filter(w => w.length > 3));
}
function similarity(a, b) {
  const A = tokenSet(a), B = tokenSet(b);
  if (!A.size || !B.size) return 0;
  let inter = 0;
  for (const t of A) if (B.has(t)) inter++;
  return inter / Math.min(A.size, B.size);
}

let duplicateOf = null;
for (const c of candidates) {
  if (c.fields['Message ID'] && c.fields['Message ID'] === ticket.messageId) {
    duplicateOf = c; break; // idempotency: already processed this exact email
  }
  const sim = Math.max(
    similarity(ticket.issue_summary, c.fields['Issue Summary']),
    similarity(ticket.subject, c.fields['Email Subject'])
  );
  if (sim >= 0.6) { duplicateOf = c; break; }
}

return [{ json: {
  ...ticket,
  is_duplicate: !!duplicateOf,
  duplicate_record_id: duplicateOf ? duplicateOf.id : null,
  duplicate_ticket_id: duplicateOf ? duplicateOf.fields['Ticket ID'] : null,
  duplicate_existing_notes: duplicateOf ? (duplicateOf.fields['Internal Notes'] || '') : '',
}, binary: $('Code - Priority Business Rules').first().binary }];

// Node: "Resolve Assignment & SLA"
// Team comes from the configurable ConfigTeamMapping table (not hardcoded);
// unmapped categories fall back to Customer Success. SLA targets mirror the
// SLATargets config table defaults.
const mapping = $input.first().json;
const ticket = $('Code - Duplicate Ticket Check').first().json;
const created = $('Airtable - Create Ticket Record').first().json;

const assignedTeam = (mapping && mapping.fields && mapping.fields['Assigned Team']) || 'Customer Success';

const SLA_ESTIMATES = {
  Critical: '1 hour',
  High: '4 hours',
  Medium: '1 business day',
  Low: '2 business days',
};

return [{ json: {
  ...ticket,
  airtable_record_id: created.id,
  ticket_id: created.fields['Ticket ID'] || created.id,
  assigned_team: assignedTeam,
  sla_estimate: SLA_ESTIMATES[ticket.priority] || '1 business day',
} }];

